public class UserService {
    private final Connection connection;

    public UserService(Connection connection) {
        this.connection = connection;
    }

    public void register(String email, String password, String card) throws Exception {
        // Responsibility 1: persistence (changes when the DBA changes schema)
        PreparedStatement ps = connection.prepareStatement(
            "INSERT INTO users(email, password) VALUES (?, ?)");
        ps.setString(1, email);
        ps.setString(2, hash(password));
        ps.executeUpdate();

        // Responsibility 2: email (changes when marketing edits the template)
        Transport.send(new MimeMessage(Session.getDefaultInstance(new Properties())) {{
            setText("Welcome " + email + "! Thanks for signing up.");
        }});

        // Responsibility 3: payment (changes when finance switches PSP)
        StripeClient stripe = new StripeClient("sk_live_...");
        stripe.charge(card, 999);
    }

    private String hash(String s) { return Integer.toHexString(s.hashCode()); }
}

public class UserRepository {
    private final Connection connection;
    public UserRepository(Connection connection) { this.connection = connection; }
    public void save(User user) throws SQLException {
        PreparedStatement ps = connection.prepareStatement(
            "INSERT INTO users(email, password_hash) VALUES (?, ?)");
        ps.setString(1, user.email());
        ps.setString(2, user.passwordHash());
        ps.executeUpdate();
    }
}

