public class RegisterUser {
    private final UserRepository repository;
    private final WelcomeMailer mailer;
    private final PaymentProcessor payments;

    public RegisterUser(UserRepository repository, WelcomeMailer mailer, PaymentProcessor payments) {
        this.repository = repository;
        this.mailer = mailer;
        this.payments = payments;
    }

    public void handle(RegistrationRequest req) throws SQLException {
        User user = User.create(req.email(), req.password());
        repository.save(user);
        payments.charge(req.paymentToken(), 999);
        mailer.sendWelcome(user.email());
    }
}

public class PaymentService {
    public void pay(String provider, long amountCents, String token) {
        switch (provider) {
            case "stripe":
                new StripeClient().charge(token, amountCents);
                break;
            case "paypal":
                new PayPalClient().execute(token, amountCents);
                break;
            // Adding Adyen forces a modification here AND re-testing the whole class.
            default:
                throw new IllegalArgumentException("Unknown provider: " + provider);
        }
    }
}

public interface PaymentProvider {
    String name();
    PaymentResult charge(long amountCents, String token);
}

public class StripeProvider implements PaymentProvider {
    public String name() { return "stripe"; }
    public PaymentResult charge(long amount, String token) {
        return new StripeClient().charge(token, amount);
    }
}

