public class PaymentService {
    private final Map<String, PaymentProvider> providers;
    public PaymentService(List<PaymentProvider> available) {
        this.providers = available.stream()
            .collect(Collectors.toMap(PaymentProvider::name, p -> p));
    }
    public PaymentResult pay(String providerName, long amountCents, String token) {
        PaymentProvider provider = providers.get(providerName);
        if (provider == null) throw new IllegalArgumentException("Unknown provider: " + providerName);
        return provider.charge(amountCents, token);
    }
}

