public interface TaxRule {
    boolean appliesTo(String countryCode);
    Money taxFor(Money subtotal);
}

public class TaxCalculator {
    private final List<TaxRule> rules;
    public TaxCalculator(List<TaxRule> rules) { this.rules = rules; }
    public Money tax(String country, Money subtotal) {
        return rules.stream()
            .filter(r -> r.appliesTo(country))
            .findFirst()
            .map(r -> r.taxFor(subtotal))
            .orElse(Money.ZERO);
    }
}

// CheckoutService now orchestrates abstractions only.
public class CheckoutService {
    private final TaxCalculator tax;
    private final PaymentProvider payment;
    private final OrderRepository orders;

    public CheckoutService(TaxCalculator tax, PaymentProvider payment, OrderRepository orders) {
        this.tax = tax; this.payment = payment; this.orders = orders;
    }

    public Receipt checkout(Cart cart) {
        Money total = cart.subtotal().plus(tax.tax(cart.country(), cart.subtotal()));
        PaymentResult result = payment.charge(total.cents(), cart.paymentToken());
        orders.save(Order.from(cart, total, result));
        return Receipt.of(result, total);
    }
}

