import java.math.BigDecimal;
import java.util.Map;

enum Tier { STANDARD, PREMIUM, VIP }

interface DiscountPolicy {
    Tier tier();
    BigDecimal discountedPrice(BigDecimal base);
}

class StandardDiscount implements DiscountPolicy {
    public Tier tier() { return Tier.STANDARD; }
    public BigDecimal discountedPrice(BigDecimal base) { return base; }
}

class PremiumDiscount implements DiscountPolicy {
    public Tier tier() { return Tier.PREMIUM; }
    public BigDecimal discountedPrice(BigDecimal base) {
        return base.multiply(new BigDecimal("0.90"));
    }
}

class VipDiscount implements DiscountPolicy {
    public Tier tier() { return Tier.VIP; }
    public BigDecimal discountedPrice(BigDecimal base) {
        return base.multiply(new BigDecimal("0.80"));
    }
}

// NEW tier = NEW class, PriceCalculator is never modified.
class PlatinumDiscount implements DiscountPolicy {
    public Tier tier() { return Tier.valueOf("VIP"); } // example placeholder if enum extended
    public BigDecimal discountedPrice(BigDecimal base) {
        return base.multiply(new BigDecimal("0.70"));
    }
}

class PriceCalculator {
    private final Map<Tier, DiscountPolicy> policies;
    PriceCalculator(java.util.List<DiscountPolicy> available) {
        this.policies = available.stream()
            .collect(java.util.stream.Collectors.toMap(DiscountPolicy::tier, p -> p));
    }
    BigDecimal finalPrice(Tier tier, BigDecimal base) {
        DiscountPolicy policy = policies.get(tier);
        if (policy == null) throw new IllegalArgumentException("No policy for tier " + tier);
        return policy.discountedPrice(base);
    }
}

import java.time.*;

interface EmailGateway {
    void send(String to, String subject, String body);
}

class NotificationService {
    private final EmailGateway gateway;
    private final Clock clock;            // java.time.Clock is itself an injectable abstraction

    NotificationService(EmailGateway gateway, Clock clock) {
        this.gateway = gateway;
        this.clock = clock;
    }

    boolean notify(String to, String subject, String body) {
        int hour = LocalTime.now(clock).getHour();
        if (hour >= 22 || hour < 7) {
            return false;                // quiet hours: suppress
        }
        gateway.send(to, subject, body);
        return true;
    }
}

// ---- Unit test (JUnit 5) ----
import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

class NotificationServiceTest {

    static class RecordingGateway implements EmailGateway {
        final List<String> sent = new ArrayList<>();
        public void send(String to, String s, String b) { sent.add(to); }
    }

    private Clock fixedAt(int hour) {
        Instant instant = LocalDate.of(2026, 6, 25)
            .atTime(hour, 0).toInstant(ZoneOffset.UTC);
        return Clock.fixed(instant, ZoneOffset.UTC);
    }

    @Test
    void suppressesDuringQuietHours() {
        RecordingGateway gateway = new RecordingGateway();
        NotificationService service = new NotificationService(gateway, fixedAt(23));
        boolean sent = service.notify("a@b.com", "Hi", "body");
        assertFalse(sent);
        assertTrue(gateway.sent.isEmpty());
    }

    @Test
    void sendsDuringDaytime() {
        RecordingGateway gateway = new RecordingGateway();
        NotificationService service = new NotificationService(gateway, fixedAt(10));
        boolean sent = service.notify("a@b.com", "Hi", "body");
        assertTrue(sent);
        assertEquals(List.of("a@b.com"), gateway.sent);
    }
}
